const int MAXN=1000;

struct node {

	int t,x,y;

};

int T(int x) {

	return x>-x?x:-x;

}

int  n;

node last,now;

int main()

{

	bool sign=0;

	scanf("%d",&n);

	for(int i=1;i<=n;i++) {

		scanf("%d%d%d",&now.t,&now.x,&now.y);

